        int parent = (index - 1) / 2;
        if (index > 0 && heap.get(parent) < heap.get(index)) {
            int temp = heap.get(parent);
            heap.set(parent, heap.get(index));
            heap.set(index, temp);
            siftUp(parent);
        }
    }

