#include <stdio.h>
#include <stdlib.h>

#define MAX_SIZE 100

typedef struct MaxHeap {
    int* heap;
    int size;
    int capacity;
} MaxHeap;

MaxHeap* createHeap() {
    MaxHeap* heap = (MaxHeap*)malloc(sizeof(MaxHeap));
    heap->heap = (int*)malloc(MAX_SIZE * sizeof(int));
    heap->size = 0;
    heap->capacity = MAX_SIZE;
    return heap;
}

void siftUp(MaxHeap* heap, int index) {
    int parent = (index - 1) / 2;
    if (index > 0 && heap->heap[parent] < heap->heap[index]) {
        int temp = heap->heap[parent];
        heap->heap[parent] = heap->heap[index];
        heap->heap[index] = temp;
        siftUp(heap, parent);
    }
}

void insert(MaxHeap* heap, int value) {
    if (heap->size < heap->capacity) {
        heap->heap[heap->size] = value;
        siftUp(heap, heap->size);
        heap->size++;
    }
}

void siftDown(MaxHeap* heap, int index) {
    int maxIndex = index;
    int left = 2 * index + 1;
    int right = 2 * index + 2;
    if (left < heap->size && heap->heap[left] > heap->heap[maxIndex]) {
        maxIndex = left;
    }
    if (right < heap->size && heap->heap[right] > heap->heap[maxIndex]) {
        maxIndex = right;
    }
    if (maxIndex != index) {
        int temp = heap->heap[index];
        heap->heap[index] = heap->heap[maxIndex];
        heap->heap[maxIndex] = temp;
        siftDown(heap, maxIndex);
    }
}

int extractMax(MaxHeap* heap) {
    if (heap->size == 0) return -1;
    int maxVal = heap->heap[0];
    heap->heap[0] = heap->heap[heap->size - 1];
    heap->size--;
    if (heap->size > 0) {
        siftDown(heap, 0);
    }
    return maxVal;
}

void printHeap(MaxHeap* heap) {
    printf("[");
    for (int i = 0; i < heap->size; i++) {
        printf("%d", heap->heap[i]);
        if (i < heap->size - 1) printf(", ");
    }
    printf("]\n");
}

int main() {
    MaxHeap* heap = createHeap();
    int values[] = {10, 5, 15};
    for (int i = 0; i < 3; i++) {
        insert(heap, values[i]);
    }
    printf("Heap after insert: ");
    printHeap(heap);
    int maxVal = extractMax(heap);
    printf("Extracted max: %d\n", maxVal);
    printf("Heap after extract: ");
    printHeap(heap);
    free(heap->heap);
    free(heap);
    return 0;
}
// Output: Heap after insert: [15, 5, 10]
// Output: Extracted max: 15
// Output: Heap after extract: [10, 5]

