class MaxHeap {
private:
    std::vector<int> heap;

    void siftUp(int index) {
        int parent = (index - 1) / 2;
        if (index > 0 && heap[parent] < heap[index]) {
            std::swap(heap[parent], heap[index]);
            siftUp(parent);
        }
    }

    void siftDown(int index) {
        int maxIndex = index;
        int left = 2 * index + 1;
        int right = 2 * index + 2;
        if (left < heap.size() && heap[left] > heap[maxIndex]) {
            maxIndex = left;
