#include <stdlib.h>

#define MAX_SIZE 100

typedef struct MaxHeap {
    int* heap;
    int size;
    int capacity;
} MaxHeap;

MaxHeap* createHeap() {
    MaxHeap* heap = (MaxHeap*)malloc(sizeof(MaxHeap));
    heap->heap = (int*)malloc(MAX_SIZE * sizeof(int));
    heap->size = 0;
    heap->capacity = MAX_SIZE;
    return heap;
}

void siftUp(MaxHeap* heap, int index) {
    int parent = (index - 1) / 2;
    if (index > 0 && heap->heap[parent] < heap->heap[index]) {
        int temp = heap->heap[parent];
        heap->heap[parent] = heap->heap[index];
        heap->heap[index] = temp;
        siftUp(heap, parent);
    }
}

void insert(MaxHeap* heap, int value) {
    if (heap->size < heap->capacity) {
        heap->heap[heap->size] = value;
        siftUp(heap, heap->size);
        heap->size++;
    }
}

void siftDown(MaxHeap* heap, int index) {
    int maxIndex = index;
    int left = 2 * index + 1;
    int right = 2 * index + 2;
    if (left < heap->size && heap->heap[left] > heap->heap[maxIndex]) {
        maxIndex = left;
    }
    if (right < heap->size && heap->heap[right] > heap->heap[maxIndex]) {
        maxIndex = right;
    }
    if (maxIndex != index) {
